                } else {
                    "Base".to_string()
                },
                if blocked {
                    format!("{position}仓位上限切到防守区间，先补数据或核验 P0。")
                } else {
                    format!("{position}维持仓位上限复核，不从单条新闻调整倍数。")
                },
                "competition score 跨档、RLDC margin 低于 38%、Other revenue share 跨 10%、监管 P0、信用层 C-TRIGGER 或筹码 P2。".to_string(),
                contradictions,
            )
        }
        "framework-review" => (
            if blocked {
                "defer".to_string()
            } else if warnings {
                "revise".to_string()
            } else {
                "keep".to_string()
            },
